package com.abc.studentportal.postgres.repository; import org.springframework.data.jpa.repository.JpaRepository; import org.springframework.data.jpa.repository.Query; import org.springframework.data.repository.query.Param; import com.abc.studentportal.postgres.entity.CourseEntity; import java.util.*; public interface CourseJpaRepository extends JpaRepository<CourseEntity,UUID>{ Optional<CourseEntity> findByCourseCode(String code); @Query("select c from CourseEntity c where c.courseCode = :code") Optional<CourseEntity> findByCode(@Param("code") String code); }
